    16→// MockLLMStorage is a simple in-memory storage implementation for testing
    17→type MockLLMStorage struct {
    18→	data map[string][]byte
    19→}
    20→
    21→func NewMockLLMStorage() *MockLLMStorage {
    22→	return &MockLLMStorage{
    23→		data: make(map[string][]byte),
    24→	}
    25→}
