    27→func (m *MockLLMStorage) Get(ctx context.Context, key string) (io.ReadCloser, error) {
    28→	data, exists := m.data[key]
    29→	if !exists {
    30→		return nil, &MockError{message: "not found"}
    31→	}
    32→	return io.NopCloser(bytes.NewReader(data)), nil
    33→}
    34→
    35→func (m *MockLLMStorage) Put(ctx context.Context, key string, reader io.Reader, opts ...PutOption) error {
    36→	data, err := io.ReadAll(reader)
    37→	if err != nil {
    38→		return err
    39→	}
    40→	m.data[key] = data
    41→	return nil
    42→}
    43→
    44→func (m *MockLLMStorage) Delete(ctx context.Context, key string) error {
    45→	delete(m.data, key)
    46→	return nil
    47→}
    48→
    49→func (m *MockLLMStorage) Exists(ctx context.Context, key string) (bool, error) {
    50→	_, exists := m.data[key]
    51→	return exists, nil
    52→}
    53→
    54→func (m *MockLLMStorage) List(ctx context.Context, opts ListOptions) ([]Object, error) {
    55→	var objects []Object
    56→	for key := range m.data {
    57→		if strings.HasPrefix(key, opts.Prefix) {
    58→			objects = append(objects, Object{
    59→				Key:  key,
    60→				Size: int64(len(m.data[key])),
    61→			})
    62→		}
    63→	}
    64→
    65→	// Apply MaxKeys limit
    66→	if opts.MaxKeys > 0 && len(objects) > opts.MaxKeys {
    67→		objects = objects[:opts.MaxKeys]
    68→	}
    69→
    70→	return objects, nil
    71→}
    72→
    73→func (m *MockLLMStorage) DeleteBatch(ctx context.Context, keys []string) error {
    74→	for _, key := range keys {
    75→		delete(m.data, key)
    76→	}
    77→	return nil
    78→}
    79→
    80→func (m *MockLLMStorage) Head(ctx context.Context, key string) (*Object, error) {
    81→	data, exists := m.data[key]
    82→	if !exists {
    83→		return nil, &MockError{message: "not found"}
    84→	}
    85→	return &Object{
    86→		Key:  key,
    87→		Size: int64(len(data)),
    88→	}, nil
